									<CheckCircle class="size-4 text-emerald-500" />
								{:else}
									<XCircle class="size-4 text-destructive" />
								{/if}
							</Table.Cell>
						</Table.Row>
					{/each}
				</Table.Body>
			</Table.Root>
		</Card.Content>
	</Card.Root>
</div>
