							<Table.Cell>
								<Badge variant={cargaVariant(pct)} class="text-xs">
									{pct >= 100 ? 'Sobrecargado' : pct >= 85 ? 'Alerta' : 'Normal'}
								</Badge>
							</Table.Cell>
						</Table.Row>
					{/each}
				</Table.Body>
			</Table.Root>
		</Card.Content>
	</Card.Root>
</div>
