/** Nivel de blindaje. */
export type ArmorLevel = 'B4' | 'B6' | 'B6+' | 'B7';

/** Estatus del ciclo de vida de la cotizacion. */
export type CotStatus = 'Borrador' | 'En Proceso' | 'En Revisión' | 'Pendiente' | 'Aprobada' | 'Rechazada';

/** Situacion operativa de la cotizacion. */
export type CotSituacion = 'Activa' | 'Por Autorizar' | 'Bloqueada' | 'Vencida';

/** Resultado del check de factibilidad. */
export type FactResult = 'Aprobada' | 'Con restricciones' | 'Pendiente' | 'No factible';

/** Estado de autorizacion comercial. */
export type AuthStatus = 'OK' | 'Pendiente';

/** Tipo de cotizacion. */
export type CotTipo = 'Blindaje + Unidad Nueva' | 'Solo Blindaje' | 'Unidad TPS de Stock';

/** Categoria de una partida. */
export type PartidaCat = 'Vehículo Stock' | 'Blindaje' | 'Accesorio' | 'Servicio';

/** Estado de una unidad de inventario. */
export type InvEstado = 'Showroom' | 'Prod. Terminado' | 'Línea de Prod.' | 'Reservado';

/** Cliente / prospecto. */
export interface Cliente {
	id: number;
	nombre: string;
	rfc: string;
	tipo: 'Persona Moral' | 'Persona Física';
	contacto: string;
	correo: string;
	tel: string;
	dom: string;
}

/** Renglon (partida) de una cotizacion. */
export interface Partida {
	desc: string;
	cat: PartidaCat;
	nivel: ArmorLevel | null;
	qty: number;
	unit: number;
	disc: number; // porcentaje 0-100
}

/** Cotizacion comercial. */
export interface Cotizacion {
	id: string;
	fecha: string; // 'YYYY-MM-DD'
	vigencia: string; // 'YYYY-MM-DD'
	version: number;
	clienteId: number | null;
	status: CotStatus;
	situacion: CotSituacion;
	modelo: string;
	blindaje: ArmorLevel | '—';
	asesor: string;
	tipo: CotTipo;
	fact: FactResult;
	auth: AuthStatus;
	total: number;
	partidas: Partida[];
	moneda?: string;
	sucursal?: string;
	diasEntrega?: number;
	/** Falsa hasta que el usuario guarda por primera vez (no aparece en el tablero). */
	persistida: boolean;
	/** Cotizacion origen si fue copiada. */
	fuenteId?: string;
}

/** Unidad de inventario. */
export interface InventarioUnidad {
	id: string;
	marca: string;
	modelo: string;
	anio: number;
	color: string;
	vin: string;
	blindaje: ArmorLevel;
	estado: InvEstado;
	disp: string;
	entrega: string;
	/** Folio de cotizacion que la reservo, o null. */
	reserva: string | null;
	precio: number;
}

/** Registro de consulta de factibilidad tecnica. */
export interface FactibilidadConsulta {
	modelo: string;
	anio: string;
	nivel: ArmorLevel;
	resultado: 'Factible' | 'Factible con restricciones' | 'No factible';
	fecha: string; // 'DD/MM/YYYY'
	respondido: string;
}

/** Precio de referencia de blindaje. */
export interface PrecioBlindaje {
	nivel: ArmorLevel;
	categoria: string;
	precio: number | null; // null = cotizacion especial
	descripcion: string;
}

/** Estado persistente del modulo de Ventas. */
export interface VentasState {
	clientes: Cliente[];
	cotizaciones: Cotizacion[];
	inventario: InventarioUnidad[];
	factibilidad: FactibilidadConsulta[];
	nextCotSeq: number;
	lastUpdated: string;
}
