	// --- CRUD cotizaciones ---
	crear(tipo: CotTipo, asesor: string, sucursal: string): Cotizacion {
		const hoy = new Date().toISOString().slice(0, 10);
		const vig = new Date(Date.now() + 15 * 864e5).toISOString().slice(0, 10);
		const nueva: Cotizacion = {
			id: folio(), fecha: hoy, vigencia: vig, version: 1, clienteId: null,
			status: 'Borrador', situacion: 'Activa', modelo: '—', blindaje: '—',
			asesor, tipo, fact: 'Pendiente', auth: 'Pendiente', total: 0, partidas: [],
			moneda: 'MXN', sucursal, persistida: false
		};
		this.state.cotizaciones = [nueva, ...this.state.cotizaciones];
		this.#commit();
		return nueva;
	}

	copiar(id: string): Cotizacion | null {
		const src = this.getCotizacion(id);
		if (!src) return null;
		const hoy = new Date().toISOString().slice(0, 10);
		const vig = new Date(Date.now() + 15 * 864e5).toISOString().slice(0, 10);
		const nueva: Cotizacion = {
			...src,
			id: folio(), fecha: hoy, vigencia: vig, version: 1,
			status: 'Borrador', situacion: 'Activa', fact: 'Pendiente', auth: 'Pendiente',
			persistida: false, fuenteId: src.id,
			partidas: src.partidas.map((p) => ({ ...p }))
		};
		this.state.cotizaciones = [nueva, ...this.state.cotizaciones];
		this.#commit();
		return nueva;
	}

	/** Aplica cambios y marca como persistida (aparece en tablero). */
	guardar(id: string, updates: Partial<Cotizacion>): Cotizacion | undefined {
		let saved: Cotizacion | undefined;
		this.state.cotizaciones = this.state.cotizaciones.map((c) => {
			if (c.id !== id) return c;
			saved = { ...c, ...updates, persistida: true };
			return saved;
		});
		this.#commit();
		return saved;
	}

	setPartidas(id: string, partidas: Partida[]) {
		const t = totalPartidas(partidas);
		this.state.cotizaciones = this.state.cotizaciones.map((c) =>
			c.id === id ? { ...c, partidas, total: t.total } : c
		);
		this.#commit();
	}

	rechazar(id: string) {
		this.state.cotizaciones = this.state.cotizaciones.map((c) =>
			c.id === id ? { ...c, status: 'Rechazada', situacion: 'Vencida' } : c
		);
		this.#commit();
	}

	avanzarPedido(id: string): string {
		this.state.cotizaciones = this.state.cotizaciones.map((c) =>
			c.id === id ? { ...c, status: 'Aprobada', situacion: 'Activa', persistida: true } : c
		);
		this.#commit();
		return 'PED-' + new Date().getFullYear() + '-' + String(Math.floor(10000 + Math.random() * 89999));
	}

	// --- Clientes ---
	buscarClientes(q: string): Cliente[] {
		const ql = (q || '').toLowerCase().trim();
		return this.state.clientes.filter((c) =>
			!ql || (c.nombre + c.rfc + c.correo + c.contacto).toLowerCase().includes(ql)
		);
	}

	clienteByRfc(rfc: string): Cliente | undefined {
		return this.state.clientes.find((c) => c.rfc === rfc.toUpperCase());
	}

	/** Alta express: si el RFC existe, devuelve el cliente sin duplicar. */
	altaExpress(data: Omit<Cliente, 'id'>): { cliente: Cliente; nuevo: boolean } {
		const existente = this.clienteByRfc(data.rfc);
		if (existente) return { cliente: existente, nuevo: false };
		const cliente: Cliente = { ...data, rfc: data.rfc.toUpperCase(), id: Math.max(0, ...this.state.clientes.map((c) => c.id)) + 1 };
		this.state.clientes = [...this.state.clientes, cliente];
		this.#commit();
		return { cliente, nuevo: true };
	}

	vincularCliente(cotId: string, clienteId: number) {
		this.state.cotizaciones = this.state.cotizaciones.map((c) =>
			c.id === cotId ? { ...c, clienteId } : c
		);
		this.#commit();
	}

	// --- Inventario ---
	get inventarioKpis() {
		const inv = this.state.inventario;
		return {
			showroom: inv.filter((u) => u.estado === 'Showroom').length,
			terminado: inv.filter((u) => u.estado === 'Prod. Terminado').length,
			linea: inv.filter((u) => u.estado === 'Línea de Prod.').length,
			reservado: inv.filter((u) => u.reserva).length
		};
	}

	reservar(uid: string, cotId: string): boolean {
		let ok = false;
		this.state.inventario = this.state.inventario.map((u) => {
			if (u.id !== uid || u.reserva) return u;
			ok = true;
			return { ...u, reserva: cotId };
		});
		if (ok) this.#commit();
		return ok;
	}

	// --- Factibilidad ---
	historialFactibilidad(modelo: string, anio: string, nivel: string): FactibilidadConsulta[] {
		const m = normalizarModelo(modelo);
		return this.state.factibilidad
			.filter((h) => normalizarModelo(h.modelo) === m && h.anio.trim() === anio.trim() && h.nivel.trim() === nivel.trim())
			.sort((x, y) => {
				const [dx, mx, yx] = x.fecha.split('/').map(Number);
				const [dy, my, yy] = y.fecha.split('/').map(Number);
				return +new Date(yy, my - 1, dy) - +new Date(yx, mx - 1, dx);
			});
	}

	/** Registra respuesta de factibilidad y actualiza la cotizacion. */
	responderFactibilidad(cotId: string, res: FactibilidadConsulta['resultado'], modelo: string, anio: string, nivel: ArmorLevel, respondido: string) {
		const map: Record<FactibilidadConsulta['resultado'], FactResult> = {
			Factible: 'Aprobada', 'Factible con restricciones': 'Con restricciones', 'No factible': 'No factible'
		};
		this.state.cotizaciones = this.state.cotizaciones.map((c) =>
			c.id === cotId ? { ...c, fact: map[res], situacion: res === 'No factible' ? 'Bloqueada' : c.situacion } : c
		);
		const d = new Date();
		const fecha = `${String(d.getDate()).padStart(2, '0')}/${String(d.getMonth() + 1).padStart(2, '0')}/${d.getFullYear()}`;
		const row: FactibilidadConsulta = { modelo, anio, nivel, resultado: res, fecha, respondido };
		const idx = this.state.factibilidad.findIndex((h) =>
			normalizarModelo(h.modelo) === normalizarModelo(modelo) && h.anio.trim() === anio.trim() && h.nivel.trim() === nivel.trim()
		);
		if (idx >= 0) this.state.factibilidad[idx] = row;
		else this.state.factibilidad = [row, ...this.state.factibilidad];
		this.#commit();
	}

	/** Marca una cotizacion como bloqueada por consulta enviada. */
	enviarConsulta(cotId: string) {
		this.state.cotizaciones = this.state.cotizaciones.map((c) =>
			c.id === cotId ? { ...c, fact: 'Pendiente', situacion: 'Bloqueada' } : c
		);
		this.#commit();
	}
}

const STORE_KEY = Symbol('ventas-store');

export function setVentasStore(): VentasStore {
	const store = new VentasStore();
	setContext(STORE_KEY, store);
	return store;
}

export function useVentasStore(): VentasStore {
	const store = getContext<VentasStore>(STORE_KEY);
	if (!store) throw new Error('useVentasStore must be used within a ventas layout');
	return store;
}

