							<div class="flex flex-wrap items-center justify-between gap-3 rounded-md border border-emerald-500/30 bg-emerald-500/5 p-4">
								<div>
									<p class="font-semibold">{cliente.nombre}</p>
									<p class="text-muted-foreground text-xs">{cliente.rfc} · {cliente.tipo}</p>
									<p class="text-muted-foreground text-xs">📞 {cliente.contacto} · ✉ {cliente.correo}</p>
								</div>
								<Button variant="outline" size="sm" onclick={() => { clienteId = null; store.vincularCliente(cot.id, null as unknown as number); }}>Cambiar cliente</Button>
							</div>
						{:else}
							<div class="relative">
								<div class="relative">
									<Search class="text-muted-foreground absolute left-3 top-1/2 size-4 -translate-y-1/2" />
									<Input bind:value={cliQuery} placeholder="Buscar cliente por nombre, RFC, correo…" class="pl-9" onfocus={() => (cliOpen = true)} oninput={() => (cliOpen = true)} />
								</div>
								{#if cliOpen}
									<div class="bg-popover absolute z-20 mt-1 w-full overflow-hidden rounded-md border shadow-lg">
										{#each cliResults as c (c.id)}
											<button class="hover:bg-muted flex w-full items-center gap-3 border-b p-3 text-left last:border-0" onclick={() => vincular(c)}>
												<Building2 class="text-muted-foreground size-4" />
												<div><p class="text-sm font-medium">{c.nombre}</p><p class="text-muted-foreground text-xs">{c.rfc} · {c.contacto} · {c.correo}</p></div>
											</button>
										{/each}
										<button class="bg-sky-500/10 hover:bg-sky-500/20 flex w-full items-center gap-3 p-3 text-left" onclick={abrirExpress}>
											<Plus class="text-sky-600 size-4" />
											<div><p class="text-sky-600 text-sm font-medium">{cliQuery ? `Crear nuevo: "${cliQuery}"` : 'Crear nuevo cliente'}</p><p class="text-muted-foreground text-xs">Dar de alta como prospecto / cliente</p></div>
										</button>
									</div>
								{/if}
							</div>
						{/if}
					</Card.Content>
				</Card.Root>

				<!-- Datos de la cotización -->
				<Card.Root>
					<Card.Header class="pb-2"><Card.Title class="text-sm">Datos de la Cotización</Card.Title></Card.Header>
					<Card.Content class="grid gap-3 sm:grid-cols-4">
						<div><Label class="text-xs">Folio</Label><Input value={cot.id} readonly class="bg-muted" /></div>
						<div><Label class="text-xs">Versión</Label><Input value={'v' + cot.version} readonly class="bg-muted" /></div>
						<div><Label class="text-xs">Fecha</Label><Input value={fechaMx(cot.fecha)} readonly class="bg-muted" /></div>
						<div><Label class="text-xs">Vigencia</Label><Input value={fechaMx(cot.vigencia)} readonly class="bg-muted" /></div>
						<div>
							<Label class="text-xs">Sucursal</Label>
							<Select.Root type="single" bind:value={sucursal}>
								<Select.Trigger>{sucursal}</Select.Trigger>
								<Select.Content>{#each SUCURSALES as s}<Select.Item value={s}>{s}</Select.Item>{/each}</Select.Content>
							</Select.Root>
						</div>
						<div class="sm:col-span-2">
							<Label class="text-xs">Tipo</Label>
							<Select.Root type="single" bind:value={tipo}>
								<Select.Trigger>{tipo}</Select.Trigger>
								<Select.Content>{#each TIPOS_COTIZACION as t}<Select.Item value={t}>{t}</Select.Item>{/each}</Select.Content>
							</Select.Root>
						</div>
						<div><Label class="text-xs">Estatus</Label><Input value={cot.status} readonly class="bg-muted" /></div>
					</Card.Content>
				</Card.Root>

				<!-- Vehículo -->
				<Card.Root>
					<Card.Header class="pb-2">
						<div class="flex items-center justify-between">
							<Card.Title class="text-sm flex items-center gap-2"><Car class="size-4" />Vehículo</Card.Title>
							<div class="flex rounded-md border p-0.5">
								<button class={cn('rounded px-3 py-1 text-xs font-medium', modalidad === 'tps' ? 'bg-primary text-primary-foreground' : 'text-muted-foreground')} onclick={() => (modalidad = 'tps')}>Unidad TPS de Stock</button>
								<button class={cn('rounded px-3 py-1 text-xs font-medium', modalidad === 'cliente' ? 'bg-primary text-primary-foreground' : 'text-muted-foreground')} onclick={() => (modalidad = 'cliente')}>Unidad del Cliente</button>
							</div>
						</div>
					</Card.Header>
					<Card.Content>
						{#if modalidad === 'tps'}
							<div class="grid gap-3 sm:grid-cols-2">
								<div class="sm:col-span-2">
									<Label class="text-xs">Unidad de stock</Label>
									<Select.Root type="single" bind:value={stockSel}>
										<Select.Trigger>{selStock ? `${selStock.id} · ${selStock.marca} ${selStock.modelo} ${selStock.anio}` : 'Seleccionar unidad de stock'}</Select.Trigger>
										<Select.Content>
											{#each stockUnits as u (u.id)}
												<Select.Item value={u.id} disabled={!!u.reserva && u.reserva !== cot.id}>{u.id} · {u.marca} {u.modelo} {u.anio} · {u.color} · {u.blindaje}{u.reserva ? ' (reservada)' : ''}</Select.Item>
											{/each}
										</Select.Content>
									</Select.Root>
								</div>
								{#if selStock}
									<div><Label class="text-xs">Blindaje</Label><Input value={selStock.blindaje} readonly class="bg-muted" /></div>
									<div><Label class="text-xs">VIN</Label><Input value={selStock.vin} readonly class="bg-muted font-mono text-xs" /></div>
									<div><Label class="text-xs">Disponibilidad</Label><Input value={selStock.disp} readonly class="bg-muted" /></div>
									<div><Label class="text-xs">Precio</Label><Input value={mxn(selStock.precio)} readonly class="bg-muted" /></div>
									<div class="sm:col-span-2"><Button size="sm" onclick={incluirUnidadTPS} disabled={!selStock}><Plus class="mr-2 size-4" />Incluir unidad en las partidas</Button></div>
								{/if}
							</div>
						{:else}
							<div class="grid gap-3 sm:grid-cols-3">
								<div><Label class="text-xs">Marca</Label><Input bind:value={cvMarca} placeholder="Ej. BMW" /></div>
								<div><Label class="text-xs">Modelo</Label><Input bind:value={cvModelo} placeholder="Ej. X5" /></div>
								<div><Label class="text-xs">Año</Label><Input bind:value={cvAnio} placeholder="2024" /></div>
								<div>
									<Label class="text-xs">Nivel de blindaje</Label>
									<Select.Root type="single" bind:value={cvBli}>
										<Select.Trigger>{cvBli}</Select.Trigger>
										<Select.Content>{#each ARMOR_LEVELS as b}<Select.Item value={b}>{b}</Select.Item>{/each}</Select.Content>
									</Select.Root>
								</div>
								<div class="sm:col-span-2"><Label class="text-xs">Valor comercial (para seguro de traslado)</Label><Input bind:value={valorComercial} placeholder="$ 850,000" /></div>
							</div>
						{/if}
						{#if requiereB7}
							<Alert.Root class="mt-3 border-destructive/40">
								<Shield class="size-4" />
								<Alert.Title>Nivel B7 — Check de Factibilidad obligatorio</Alert.Title>
								<Alert.Description>La cotización no puede avanzar a pedido sin validación técnica de Ingeniería.</Alert.Description>
							</Alert.Root>
						{/if}
					</Card.Content>
				</Card.Root>

				<!-- Partidas + resumen -->
				<div class="grid gap-5 lg:grid-cols-[1fr_300px]">
					<Card.Root class="h-fit">
						<Card.Header class="pb-2">
							<div class="flex items-center justify-between">
								<Card.Title class="text-sm">Partidas</Card.Title>
								<Button size="sm" variant="outline" onclick={() => (partidaOpen = true)}><Plus class="mr-2 size-4" />Nueva partida</Button>
							</div>
						</Card.Header>
						<Card.Content>
							<Table.Root>
								<Table.Header>
									<Table.Row>
										<Table.Head class="w-8">#</Table.Head>
										<Table.Head>Descripción</Table.Head>
										<Table.Head>Categoría</Table.Head>
										<Table.Head>Nivel</Table.Head>
										<Table.Head class="text-right">Cant.</Table.Head>
										<Table.Head class="text-right">P. Unitario</Table.Head>
										<Table.Head class="text-right">Desc.</Table.Head>
										<Table.Head class="text-right">Total</Table.Head>
										<Table.Head></Table.Head>
									</Table.Row>
								</Table.Header>
								<Table.Body>
									{#each partidas as p, i (i)}
										<Table.Row>
											<Table.Cell class="text-muted-foreground">{i + 1}</Table.Cell>
											<Table.Cell class="text-sm font-medium">{p.desc}{#if p.cat === 'Blindaje'}<p class="text-muted-foreground text-xs">Incluido en paquete</p>{/if}</Table.Cell>
											<Table.Cell><Badge variant="outline" class="text-xs">{p.cat}</Badge></Table.Cell>
											<Table.Cell>{#if p.nivel}<Badge variant="outline" class={ARMOR_BADGE[p.nivel]}>{p.nivel}</Badge>{:else}—{/if}</Table.Cell>
											<Table.Cell class="text-right tabular-nums">{p.qty}</Table.Cell>
											<Table.Cell class="text-right tabular-nums text-sm">{p.unit > 0 ? mxn(p.unit) : 'Incluido'}</Table.Cell>
											<Table.Cell class="text-right tabular-nums text-sm">{p.disc > 0 ? p.disc + '%' : '—'}</Table.Cell>
											<Table.Cell class="text-right font-medium tabular-nums">{p.unit > 0 ? mxn(lineTotal(p)) : 'Incluido'}</Table.Cell>
											<Table.Cell><Button size="icon" variant="ghost" class="size-7 text-destructive" onclick={() => eliminarPartida(i)}><Trash2 class="size-3" /></Button></Table.Cell>
										</Table.Row>
									{/each}
								</Table.Body>
							</Table.Root>
							{#if partidas.length === 0}<p class="text-muted-foreground py-6 text-center text-sm">Sin partidas. Agrega una unidad o partida.</p>{/if}
						</Card.Content>
					</Card.Root>

					<!-- Resumen -->
					<div class="space-y-4">
						<Card.Root>
							<Card.Header class="pb-2"><Card.Title class="text-sm">Resumen</Card.Title></Card.Header>
							<Card.Content class="space-y-2 text-sm">
								<div class="flex justify-between"><span class="text-muted-foreground">Subtotal</span><span class="tabular-nums">{mxn(totals.sub)}</span></div>
								<div class="flex justify-between"><span class="text-muted-foreground">Descuento</span><span class="tabular-nums text-destructive">− {mxn(totals.disc)}</span></div>
								<div class="flex justify-between"><span class="text-muted-foreground">IVA (16%)</span><span class="tabular-nums">{mxn(totals.iva)}</span></div>
								<Separator />
								<div class="flex justify-between text-base font-bold"><span>Total</span><span class="tabular-nums">{mxn(totals.total)}</span></div>
							</Card.Content>
						</Card.Root>

						<Card.Root>
							<Card.Header class="pb-2"><Card.Title class="text-sm">Margen estimado</Card.Title></Card.Header>
							<Card.Content>
								<div class="flex items-center justify-between text-sm"><span class="text-muted-foreground">Margen</span><span class={cn('font-bold tabular-nums', margen >= 70 ? 'text-emerald-600' : margen >= 50 ? 'text-amber-600' : 'text-destructive')}>{margen}%</span></div>
								<div class="mt-1 h-1.5 w-full overflow-hidden rounded-full bg-muted">
									<div class={cn('h-full rounded-full', margen >= 70 ? 'bg-emerald-500' : margen >= 50 ? 'bg-amber-400' : 'bg-destructive')} style="width:{margen}%"></div>
								</div>
								{#if descuentoAlto}<p class="text-destructive mt-2 flex items-center gap-1 text-xs"><Lock class="size-3" />Descuento &gt;{DISCOUNT_THRESHOLD}% requiere autorización del Gerente Comercial</p>{/if}
							</Card.Content>
						</Card.Root>

						<Card.Root>
							<Card.Header class="pb-2"><Card.Title class="text-sm">Tiempo de entrega</Card.Title></Card.Header>
							<Card.Content>
								<div class="flex items-center gap-2">
									<Input type="number" bind:value={diasEntrega} class="w-24" />
									<span class="text-muted-foreground text-sm">días hábiles</span>
								</div>
								{#if entregaAlerta}<p class="text-amber-600 mt-2 flex items-center gap-1 text-xs"><TriangleAlert class="size-3" />Menor al estándar ({MIN_DIAS_ENTREGA} días) — requiere autorización</p>{:else}<p class="text-emerald-600 mt-2 flex items-center gap-1 text-xs"><Check class="size-3" />Dentro del estándar</p>{/if}
							</Card.Content>
						</Card.Root>
					</div>
				</div>
			</Tabs.Content>

			<!-- ══ TAB FACTIBILIDAD ══ -->
			<Tabs.Content value="factibilidad" class="mt-4 space-y-5">
				<Alert.Root>
					<Car class="size-4" />
					<Alert.Title>Vehículo de esta cotización</Alert.Title>
					<Alert.Description>{vehiculoResumen.modelo} · {vehiculoResumen.anio} · {vehiculoResumen.blindaje}</Alert.Description>
				</Alert.Root>

				<Card.Root>
					<Card.Header class="pb-2">
						<div class="flex items-center justify-between">
							<Card.Title class="text-sm flex items-center gap-2"><Shield class="size-4" />Check de Factibilidad Técnica <Badge variant="outline" class="font-mono text-xs">GAP-VTA-002</Badge></Card.Title>
							<Badge variant={FACT_META[cot.fact].variant} class={FACT_META[cot.fact].badge}>{FACT_META[cot.fact].label}</Badge>
						</div>
					</Card.Header>
					<Card.Content class="space-y-3">
						{#if cot.fact === 'Pendiente'}
							<Alert.Root class="border-amber-500/40"><TriangleAlert class="size-4" /><Alert.Title>Cotización bloqueada</Alert.Title><Alert.Description>No puede avanzar a pedido hasta recibir respuesta de Ingeniería.</Alert.Description></Alert.Root>
						{:else if cot.fact === 'No factible'}
							<Alert.Root class="border-destructive/40"><CircleX class="size-4" /><Alert.Title>No factible</Alert.Title><Alert.Description>Ingeniería determinó que la combinación no es viable. Bloqueada.</Alert.Description></Alert.Root>
						{:else}
							<Alert.Root class="border-emerald-500/40"><Check class="size-4" /><Alert.Title>Factible {cot.fact === 'Con restricciones' ? 'con restricciones' : ''}</Alert.Title><Alert.Description>Ingeniería aprobó: {vehiculoResumen.modelo} · {vehiculoResumen.blindaje}.</Alert.Description></Alert.Root>
						{/if}
						<div class="flex flex-wrap items-end gap-3">
							<div>
								<Label class="text-xs">Resultado</Label>
								<Select.Root type="single" bind:value={factResultado}>
									<Select.Trigger class="w-56">{factResultado}</Select.Trigger>
									<Select.Content>
										<Select.Item value="Factible">Factible</Select.Item>
										<Select.Item value="Factible con restricciones">Factible con restricciones</Select.Item>
										<Select.Item value="No factible">No factible</Select.Item>
									</Select.Content>
								</Select.Root>
							</div>
							<div><Label class="text-xs">Respondido por</Label><Input bind:value={factRespondido} class="w-48" /></div>
							<Button variant="outline" onclick={guardarRespuesta}>Registrar respuesta</Button>
							<Button onclick={() => (consultaOpen = true)}><Plus class="mr-2 size-4" />Nueva consulta</Button>
						</div>
					</Card.Content>
				</Card.Root>

				<Card.Root>
					<Card.Header class="pb-2"><Card.Title class="text-sm">Historial de Consultas</Card.Title></Card.Header>
					<Card.Content>
						<Table.Root>
							<Table.Header>
								<Table.Row><Table.Head>Modelo</Table.Head><Table.Head>Año</Table.Head><Table.Head>Nivel</Table.Head><Table.Head>Resultado</Table.Head><Table.Head>Fecha</Table.Head><Table.Head>Respondido</Table.Head></Table.Row>
							</Table.Header>
							<Table.Body>
								{#each factHistorial as h, i (i)}
									<Table.Row class={i === 0 ? 'bg-emerald-500/5' : ''}>
										<Table.Cell class="font-medium text-sm">{h.modelo}</Table.Cell>
										<Table.Cell class="text-sm">{h.anio}</Table.Cell>
										<Table.Cell><Badge variant="outline" class={ARMOR_BADGE[h.nivel]}>{h.nivel}</Badge></Table.Cell>
										<Table.Cell>
											{#if h.resultado === 'Factible'}<Badge variant="secondary" class="text-emerald-600">✔ Factible</Badge>
											{:else if h.resultado === 'Factible con restricciones'}<Badge variant="outline" class="text-amber-600">⚡ Con restricciones</Badge>
											{:else}<Badge variant="destructive">✘ No factible</Badge>{/if}
										</Table.Cell>
										<Table.Cell class="text-muted-foreground text-sm">{h.fecha}</Table.Cell>
										<Table.Cell class="text-sm">{h.respondido}</Table.Cell>
									</Table.Row>
								{/each}
							</Table.Body>
						</Table.Root>
						{#if factHistorial.length === 0}<p class="text-muted-foreground py-6 text-center text-sm">Sin historial para este vehículo cotizado.</p>{/if}
					</Card.Content>
				</Card.Root>
			</Tabs.Content>

			<!-- ══ TAB VERSIONES ══ -->
			<Tabs.Content value="versiones" class="mt-4">
				<Card.Root>
					<Card.Header class="pb-2">
						<div class="flex items-center justify-between">
							<Card.Title class="text-sm">Historial de Versiones</Card.Title>
							<Badge variant="outline">{cot.version} versiones</Badge>
						</div>
					</Card.Header>
					<Card.Content>
						<div class="relative space-y-4 pl-6">
							<div class="bg-border absolute bottom-2 left-2 top-2 w-px"></div>
							{#each Array.from({ length: cot.version }, (_, i) => cot.version - i) as v}
								<div class="relative">
									<div class={cn('absolute -left-4.5 top-1 size-3 rounded-full border-2', v === cot.version ? 'border-primary bg-primary/20' : 'border-muted-foreground/40 bg-background')}></div>
									<div class="rounded-md border p-3">
										<div class="flex items-center gap-2">
											<span class="font-semibold text-sm">v{String(v).padStart(2, '0')}</span>
											{#if v === cot.version}<Badge variant="secondary">Actual</Badge>{/if}
											<span class="text-muted-foreground text-xs">{fechaMx(cot.fecha)}</span>
										</div>
										<p class="text-muted-foreground mt-1 text-xs">{v === cot.version ? 'Versión vigente en edición' : 'Cambio de precio / partidas registrado automáticamente'}</p>
									</div>
								</div>
							{/each}
						</div>
					</Card.Content>
				</Card.Root>
			</Tabs.Content>
		</Tabs.Root>
	</div>

	<!-- ══ Modales ══ -->
	<Dialog.Root bind:open={partidaOpen}>
		<Dialog.Content class="max-w-lg">
			<Dialog.Header><Dialog.Title>Nueva Partida</Dialog.Title></Dialog.Header>
			<div class="grid gap-3 sm:grid-cols-3">
				<div class="sm:col-span-3"><Label class="text-xs">Descripción</Label><Input bind:value={npDesc} placeholder="Ej. Accesorio Premium — Intercom blindado" /></div>
				<div>
					<Label class="text-xs">Categoría</Label>
					<Select.Root type="single" bind:value={npCat}>
						<Select.Trigger>{npCat}</Select.Trigger>
						<Select.Content>{#each PARTIDA_CATS as c}<Select.Item value={c}>{c}</Select.Item>{/each}</Select.Content>
					</Select.Root>
				</div>
				<div>
					<Label class="text-xs">Nivel</Label>
					<Select.Root type="single" bind:value={npNivel}>
						<Select.Trigger>{npNivel}</Select.Trigger>
						<Select.Content><Select.Item value="—">—</Select.Item>{#each ARMOR_LEVELS as b}<Select.Item value={b}>{b}</Select.Item>{/each}</Select.Content>
					</Select.Root>
				</div>
				<div><Label class="text-xs">Cantidad</Label><Input type="number" bind:value={npQty} min="1" /></div>
				<div><Label class="text-xs">Precio Unitario</Label><Input type="number" bind:value={npUnit} min="0" step="1000" /></div>
				<div><Label class="text-xs">Descuento (%)</Label><Input type="number" bind:value={npDisc} min="0" max="100" /></div>
			</div>
			<Dialog.Footer>
				<Button variant="outline" onclick={() => (partidaOpen = false)}>Cancelar</Button>
				<Button onclick={agregarPartida}>Guardar partida</Button>
			</Dialog.Footer>
		</Dialog.Content>
	</Dialog.Root>

	<!-- Alta express cliente -->
	<Dialog.Root bind:open={expressOpen}>
		<Dialog.Content class="max-w-lg">
			<Dialog.Header><Dialog.Title>Alta Express de Cliente</Dialog.Title><Dialog.Description>Se vincula automáticamente. Si el RFC ya existe, no se duplica.</Dialog.Description></Dialog.Header>
			<div class="grid gap-3 sm:grid-cols-2">
				<div class="sm:col-span-2"><Label class="text-xs">Nombre / Razón social *</Label><Input bind:value={xNombre} /></div>
				<div>
					<Label class="text-xs">RFC *</Label>
					<Input bind:value={xRfc} class="uppercase" oninput={(e) => (xRfc = e.currentTarget.value.toUpperCase())} />
					{#if rfcExistente}<p class="text-amber-600 mt-1 text-xs">⚡ RFC ya registrado: {rfcExistente.nombre} — se vinculará sin duplicar</p>{/if}
				</div>
				<div>
					<Label class="text-xs">Tipo</Label>
					<Select.Root type="single" bind:value={xTipo}>
						<Select.Trigger>{xTipo}</Select.Trigger>
						<Select.Content><Select.Item value="Persona Moral">Persona Moral</Select.Item><Select.Item value="Persona Física">Persona Física</Select.Item></Select.Content>
					</Select.Root>
				</div>
				<div><Label class="text-xs">Contacto *</Label><Input bind:value={xContacto} /></div>
				<div><Label class="text-xs">Correo *</Label><Input bind:value={xCorreo} type="email" /></div>
				<div><Label class="text-xs">Teléfono</Label><Input bind:value={xTel} /></div>
				<div><Label class="text-xs">Domicilio</Label><Input bind:value={xDom} /></div>
			</div>
			<Dialog.Footer>
				<Button variant="outline" onclick={() => (expressOpen = false)}>Cancelar</Button>
				<Button onclick={guardarExpress}>Guardar y vincular</Button>
			</Dialog.Footer>
		</Dialog.Content>
	</Dialog.Root>

	<!-- PDF -->
	<Dialog.Root bind:open={pdfOpen}>
		<Dialog.Content class="max-w-md">
			<Dialog.Header><Dialog.Title>Generar PDF Corporativo</Dialog.Title></Dialog.Header>
			<div class="space-y-2">
				{#each ['Datos del cliente', 'Partidas y precios', 'Términos y condiciones TPS', 'Catálogo de niveles de blindaje'] as opt, i}
					<label class="flex items-center gap-2 text-sm"><input type="checkbox" checked={i < 3} class="accent-primary" />{opt}</label>
				{/each}
			</div>
			<Dialog.Footer>
				<Button variant="outline" onclick={() => (pdfOpen = false)}>Cancelar</Button>
				<Button onclick={() => { pdfOpen = false; toast.success('PDF generado con la información actual'); }}><FileDown class="mr-2 size-4" />Generar y descargar</Button>
			</Dialog.Footer>
		</Dialog.Content>
	</Dialog.Root>

	<!-- Email -->
	<Dialog.Root bind:open={emailOpen}>
		<Dialog.Content class="max-w-lg">
			<Dialog.Header><Dialog.Title>Enviar por Correo</Dialog.Title></Dialog.Header>
			<div class="space-y-3">
				<div><Label class="text-xs">Para</Label><Input value={cliente?.correo ?? ''} /></div>
				<div><Label class="text-xs">Asunto</Label><Input value={`Cotización TPS — ${cot.id} v${cot.version} · ${cot.modelo}`} /></div>
				<div><Label class="text-xs">Mensaje</Label><Textarea class="min-h-28" value={`Estimado cliente,\n\nAdjuntamos la cotización actualizada para su revisión.\n\nQuedo a sus órdenes.\n${cot.asesor} | Área de Ventas — TPS`} /></div>
			</div>
			<Dialog.Footer>
				<Button variant="outline" onclick={() => (emailOpen = false)}>Cancelar</Button>
				<Button onclick={() => { emailOpen = false; toast.success('Correo enviado con PDF adjunto'); }}><Mail class="mr-2 size-4" />Enviar correo</Button>
			</Dialog.Footer>
		</Dialog.Content>
	</Dialog.Root>

	<!-- Firma -->
	<Dialog.Root bind:open={firmaOpen}>
		<Dialog.Content class="max-w-md">
			<Dialog.Header><Dialog.Title>Firma Electrónica</Dialog.Title></Dialog.Header>
			<Alert.Root><PenLine class="size-4" /><Alert.Description>Solicitud con enlace seguro (OTP) enviada a ambas partes.</Alert.Description></Alert.Root>
			<div class="grid gap-3 sm:grid-cols-2">
				<div><Label class="text-xs">Firmante 1 — Cliente</Label><Input value={cliente?.contacto ?? '—'} readonly class="bg-muted" /></div>
				<div><Label class="text-xs">Firmante 2 — TPS</Label><Input value={cot.asesor} readonly class="bg-muted" /></div>
			</div>
			<Dialog.Footer>
				<Button variant="outline" onclick={() => (firmaOpen = false)}>Cancelar</Button>
				<Button onclick={() => { firmaOpen = false; toast.success('Solicitud de firma enviada'); }}><PenLine class="mr-2 size-4" />Enviar solicitud</Button>
			</Dialog.Footer>
		</Dialog.Content>
	</Dialog.Root>

	<!-- Rechazo -->
	<Dialog.Root bind:open={rechazoOpen}>
		<Dialog.Content class="max-w-md">
			<Dialog.Header><Dialog.Title>Rechazar Cotización</Dialog.Title></Dialog.Header>
			<Alert.Root class="border-destructive/40"><TriangleAlert class="size-4" /><Alert.Description>Al rechazar, la cotización se cierra definitivamente. El motivo es obligatorio.</Alert.Description></Alert.Root>
			<div class="space-y-3">
				<div>
					<Label class="text-xs">Motivo *</Label>
					<Select.Root type="single" bind:value={motivoRec}>
						<Select.Trigger>{motivoRec || 'Seleccionar motivo'}</Select.Trigger>
						<Select.Content>{#each MOTIVOS_RECHAZO as m}<Select.Item value={m}>{m}</Select.Item>{/each}</Select.Content>
					</Select.Root>
				</div>
				<div><Label class="text-xs">Comentarios</Label><Textarea bind:value={comentRec} class="min-h-20" placeholder="Detalles del motivo…" /></div>
			</div>
			<Dialog.Footer>
				<Button variant="outline" onclick={() => (rechazoOpen = false)}>Cancelar</Button>
				<Button variant="destructive" onclick={confirmarRechazo}>Confirmar rechazo</Button>
			</Dialog.Footer>
		</Dialog.Content>
	</Dialog.Root>

	<!-- Consulta factibilidad -->
	<Dialog.Root bind:open={consultaOpen}>
		<Dialog.Content class="max-w-lg">
			<Dialog.Header><Dialog.Title>Nueva Consulta de Factibilidad</Dialog.Title></Dialog.Header>
			<Alert.Root class="border-amber-500/40"><TriangleAlert class="size-4" /><Alert.Description>Al enviar, la cotización quedará <strong>bloqueada</strong> hasta recibir respuesta de Ingeniería.</Alert.Description></Alert.Root>
			<div class="grid gap-3 sm:grid-cols-3">
				<div><Label class="text-xs">Marca</Label><Input bind:value={ckMarca} placeholder="Porsche" /></div>
				<div><Label class="text-xs">Modelo</Label><Input bind:value={ckModelo} placeholder="Cayenne GTS" /></div>
				<div><Label class="text-xs">Año</Label><Input bind:value={ckAnio} placeholder="2025" /></div>
				<div>
					<Label class="text-xs">Nivel</Label>
					<Select.Root type="single" bind:value={ckNivel}>
						<Select.Trigger>{ckNivel}</Select.Trigger>
						<Select.Content>{#each ARMOR_LEVELS as b}<Select.Item value={b}>{b}</Select.Item>{/each}</Select.Content>
					</Select.Root>
				</div>
			</div>
			<Dialog.Footer>
				<Button variant="outline" onclick={() => (consultaOpen = false)}>Cancelar</Button>
				<Button onclick={enviarConsulta}>Enviar consulta</Button>
			</Dialog.Footer>
		</Dialog.Content>
	</Dialog.Root>

	<!-- Avanzar a pedido -->
	<Dialog.Root bind:open={pedidoModal}>
		<Dialog.Content class="max-w-md">
			<Dialog.Header><Dialog.Title>Avanzar a Pedido / Orden de Venta</Dialog.Title></Dialog.Header>
			<Alert.Root><Check class="size-4" /><Alert.Description>Se validarán todas las condiciones (cliente, factibilidad, inventario) antes de proceder.</Alert.Description></Alert.Root>
			<Dialog.Footer>
				<Button variant="outline" onclick={() => (pedidoModal = false)}>Cancelar</Button>
				<Button onclick={confirmarPedido}>Confirmar avance</Button>
			</Dialog.Footer>
		</Dialog.Content>
	</Dialog.Root>
{/if}
